 1→import React from 'react';
 2→import * as echarts from 'echarts/core';
 3→import type { SetOptionOpts } from 'echarts/core';
 4→
 5→export { echarts };
 6→
 7→export type EChartsCore = typeof echarts;
 8→
 9→export interface ChartContextValue {
10→  options: echarts.EChartsCoreOption[];
11→}
12→
13→export const defaultSetOptionOpt: SetOptionOpts = {
14→  notMerge: false,
15→  lazyUpdate: true,
16→};
17→
18→export const ChartContext = React.createContext<ChartContextValue | null>(null);
19→
20→export const useInitialChartContext = () => {
21→  const [chartContextValue] = React.useState<ChartContextValue>(() => ({
22→    options: [],
23→  }));
24→  return chartContextValue;
25→};
26→
27→export const useChartContext = () => {
28→  const ctx = React.useContext(ChartContext);
29→  if (process.env.NODE_ENV === 'development' && !ctx)
30→    throw new Error('The component should render within ChartContext');
31→  return ctx!;
32→};
33→
34→export function useRegister(fn: (echarts: EChartsCore) => void) {
35→  const isExecuted = React.useRef(false);
36→  if (isExecuted.current) return;
37→  isExecuted.current = true;
38→  fn(echarts);
39→}
40→
41→export type EChartExt = Parameters<(typeof echarts)['use']>[0];
42→
43→export type Simplify<T> = { [K in keyof T]: T[K] } & {};
44→

  1→import React from 'react';
  2→import type {
  3→  BarSeriesOption,
  4→  ComposeOption,
  5→  EffectScatterSeriesOption,
  6→  GraphSeriesOption,
  7→  GridComponentOption,
  8→  HeatmapSeriesOption,
  9→  LineSeriesOption,
 10→  PieSeriesOption,
 11→  ScatterSeriesOption,
 12→} from 'echarts';
 13→import {
 14→  BarChart as EChartBarChart,
 15→  EffectScatterChart as EChartEffectScatterChart,
 16→  GraphChart as EChartGraphChart,
 17→  HeatmapChart as EChartHeatmapChart,
 18→  LineChart as EChartLineChart,
 19→  PieChart as EChartPieChart,
 20→  ScatterChart as EChartScatterChart,
 21→} from 'echarts/charts';
 22→import { GridComponent } from 'echarts/components';
 23→import type { ComponentOption } from 'echarts/types/src/util/types.js';
 24→import {
 25→  ChartContext,
 26→  defaultSetOptionOpt,
 27→  echarts,
 28→  useInitialChartContext,
 29→  useRegister,
 30→  type EChartExt,
 31→  type Simplify,
 32→} from './shared.js';
 33→
 34→function assignForwardedRef<T>(ref: React.ForwardedRef<T>, value: T | null) {
 35→  if (!ref) return;
 36→  if (typeof ref === 'function') ref(value);
 37→  else ref.current = value;
 38→}
 39→
 40→interface ChartBaseProps<T extends readonly ChartComponentType[]> {
 41→  className?: string;
 42→  style?: React.CSSProperties;
 43→  containerProps?: React.HTMLAttributes<HTMLDivElement>;
 44→  compose?: [...T];
 45→  use?: EChartExt;
 46→  children?: React.ReactNode;
 47→}
 48→
 49→type ResolveComponentOption<T extends ComponentOption | ChartComponentType> = T extends ComponentOption
 50→  ? T
 51→  : T extends ChartComponentType<infer P>
 52→  ? P
 53→  : never;
 54→
 55→interface ChartComponentType<in T extends ComponentOption = any> {
 56→  <U extends readonly ChartComponentType[] = []>(
 57→    props: ChartBaseProps<U> &
 58→      echarts.EChartsCoreOption &
 59→      Simplify<ComposeOption<ResolveComponentOption<T | U[number]>>> & {
 60→        ref?: React.Ref<echarts.ECharts>;
 61→      }
 62→  ): React.JSX.Element;
 63→
 64→  ext: EChartExt;
 65→}
 66→
 67→function defineChart<T extends ComponentOption>(ext: EChartExt) {
 68→  const ChartComponent = React.forwardRef(
 69→    (
 70→      { className, style, containerProps, compose, use, children, ...props }: ChartBaseProps<any>,
 71→      ref: React.ForwardedRef<echarts.ECharts>
 72→    ) => {
 73→      const containerRef = React.useRef<HTMLDivElement>(null);
 74→      const chartRef = React.useRef<echarts.ECharts | null>(null);
 75→      const ctx = useInitialChartContext();
 76→
 77→      useRegister((echarts) => {
 78→        echarts.use([ext, use, compose?.map((comp) => comp.ext).flat() || []].flat().filter(Boolean));
 79→      });
 80→
 81→      React.useLayoutEffect(() => {
 82→        const chart = (chartRef.current = echarts.init(containerRef.current, null));
 83→        assignForwardedRef(ref, chart);
 84→        return () => {
 85→          chart.dispose();
 86→          assignForwardedRef(ref, null);
 87→        };
 88→      }, []);
 89→
 90→      React.useLayoutEffect(() => {
 91→        const chart = chartRef.current;
 92→        if (!chart) return;
 93→        for (const opt of ctx.options) chart.setOption(opt, defaultSetOptionOpt);
 94→        chart.setOption(props, defaultSetOptionOpt);
 95→        chart.setOption(chart.getOption(), { notMerge: true }); // used for toolbox.restore snapshot
 96→        ctx.options.length = 0;
 97→      });
 98→
 99→      return (
100→        <ChartContext.Provider value={ctx}>
101→          <div className={className} style={style} {...containerProps} ref={containerRef} />
102→          {children}
103→        </ChartContext.Provider>
104→      );
105→    }
106→  ) as unknown as ChartComponentType<T>;
107→  ChartComponent.ext = ext;
108→  return ChartComponent;
109→}
110→
111→export const BarChart = /*#__PURE__*/ defineChart<BarSeriesOption | GridComponentOption>([
112→  EChartBarChart,
113→  GridComponent,
114→]);
115→
116→export const EffectScatterChart = /*#__PURE__*/ defineChart<EffectScatterSeriesOption | GridComponentOption>([
117→  EChartEffectScatterChart,
118→  GridComponent,
119→]);
120→
121→export const GraphChart = /*#__PURE__*/ defineChart<GraphSeriesOption>([EChartGraphChart]);
122→
123→export const HeatmapChart = /*#__PURE__*/ defineChart<HeatmapSeriesOption>([EChartHeatmapChart]);
124→
125→export const LineChart = /*#__PURE__*/ defineChart<LineSeriesOption | GridComponentOption>([
126→  EChartLineChart,
127→  GridComponent,
128→]);
129→
130→export const PieChart = /*#__PURE__*/ defineChart<PieSeriesOption>([EChartPieChart]);
131→
132→export const ScatterChart = /*#__PURE__*/ defineChart<ScatterSeriesOption | GridComponentOption>([
133→  EChartScatterChart,
134→  GridComponent,
135→]);
