 1→import { BarChart, LineChart, PieChart } from '@fanciers/echarts-react';
 2→import type {
 3→  BarSeriesOption,
 4→  LineSeriesOption,
 5→  PieSeriesOption,
 6→  XAXisComponentOption,
 7→  YAXisComponentOption,
 8→} from 'echarts';
 9→import { describe, it, expectTypeOf } from 'vitest';
10→
11→type Arrayable<T> = T | T[];
12→
13→describe('TypeScript Definitions', () => {
14→  it('should accept basic props', () => {
15→    expectTypeOf(LineChart).toBeFunction();
16→    expectTypeOf(LineChart<[]>)
17→      .parameter(0)
18→      .pick<'xAxis' | 'yAxis' | 'series'>()
19→      .toEqualTypeOf<{
20→        xAxis?: Arrayable<XAXisComponentOption>;
21→        yAxis?: Arrayable<YAXisComponentOption>;
22→        series?: Arrayable<LineSeriesOption>;
23→      }>();
24→  });
25→
26→  it('should support compose single chart', () => {
27→    expectTypeOf(LineChart<[typeof BarChart]>)
28→      .parameter(0)
29→      .pick<'series'>()
30→      .toEqualTypeOf<{ series?: Arrayable<LineSeriesOption | BarSeriesOption> }>();
31→  });
32→
33→  it('should support compose multiple charts', () => {
34→    expectTypeOf(LineChart<[typeof BarChart, typeof PieChart]>)
35→      .parameter(0)
